let input;
if (msg.req && msg.req.body) {
    input = msg.req.body;
    msg._fromHttp = true;
} else {
    input = msg.payload;
    msg._fromHttp = false;
}

// Daftar IP Hardcoded untuk Pengujian Awal
const machineMap = {
    "MC01": "172.70.66.195", "MC02": "172.70.66.184", "MC03": "172.70.66.186",
    "MC04": "172.70.66.188", "MC05": "172.70.66.190", "MC06": "172.70.66.194",
    "MC07": "172.25.72.41", "MC08": "172.25.72.43", "MC09": "172.25.72.45",
    "MC10": "172.25.72.47"
};

const svRegisterMap = {
    "UP_SV_01": 6101, "UP_SV_02": 6201, "UP_SV_03": 6301, "UP_SV_04": 6401,
    "UP_SV_05": 6501, "UP_SV_06": 6601, "UP_SV_07": 6701, "UP_SV_08": 6801,
    "DOWN_SV_01": 6901, "DOWN_SV_02": 7001, "DOWN_SV_03": 7101, "DOWN_SV_04": 7201,
    "DOWN_SV_05": 7301, "DOWN_SV_06": 7401, "DOWN_SV_07": 7501, "DOWN_SV_08": 7601,
    "UP_SPEED_SV": 7800, "DOWN_SPEED_SV": 7700
};

const { machineId, variable, value } = input;

if (!machineId || !variable || value === undefined) {
    node.error("Input tidak lengkap: butuh machineId, variable, value");
    msg._writeError = "Input tidak lengkap";
    return msg;
}

const targetIp = machineMap[machineId];
if (!targetIp) {
    node.error(`machineId tidak dikenal: ${machineId}`);
    msg._writeError = `machineId tidak dikenal: ${machineId}`;
    return msg;
}

const registerAddress = svRegisterMap[variable];
if (registerAddress === undefined) {
    node.error(`Variabel bukan SV atau tidak dikenal: ${variable}`);
    msg._writeError = `Hanya variabel SV yang bisa ditulis. '${variable}' tidak dikenal.`;
    return msg;
}

const numericValue = parseFloat(value);
if (isNaN(numericValue)) {
    node.error(`Nilai tidak valid: ${value}`);
    msg._writeError = `Nilai tidak valid: ${value}`;
    return msg;
}

// Penskalaan nilai desimal dikali 10 ke format Integer asli PLC
const rawWrite = Math.round(numericValue * 10);

if (rawWrite < 0 || rawWrite > 9999) {
    node.error(`Nilai di luar batas: ${numericValue}`);
    msg._writeError = 'Nilai di luar batas yang diizinkan';
    return msg;
}

msg.payload = {
    fc: 6,
    unitid: 1,
    address: registerAddress,
    value: rawWrite
};

msg.modbusHost = targetIp;
msg.modbusPort = 502;

// Cadangkan metadata agar aman dari over-write node Modbus Write
msg._writeAddress = registerAddress;
msg._writeRawValue = rawWrite;
msg._writeMachineId = machineId;
msg._writeVariable = variable;

return msg;

if (msg._fromHttp) {
    msg.statusCode = 200;
    msg.payload = {
        success: true,
        message: "Write Modbus ke PLC berhasil",
        targetIp: msg.modbusHost,
        machineId: msg._writeMachineId,
        variable: msg._writeVariable,
        address: msg._writeAddress,
        rawValue: msg._writeRawValue
    };
    return msg;
}
return null;

let errorMessage = msg.error ? msg.error.message : (msg._writeError || "Modbus Timeout/Connection Error");

if (msg._fromHttp) {
    msg.statusCode = 500;
    msg.payload = {
        success: false,
        message: "Gagal menulis ke PLC: " + errorMessage,
        machineId: msg._writeMachineId || "Unknown"
    };
    return msg;
}
return null;
